// === Social Budget — daily Slack pacing / wasted-spend / ROAS digest =========
// Reads the published "Budget Tracker (Import)" CSV from the HTTP Request node
// (set that node's Response Format = "Text") and builds one Slack message:
// a portfolio digest plus only the sections that have something to flag.
// All thresholds are tunable below.

// ---- tunables ---------------------------------------------------------------
const OVERPACE_PTS    = 0.05;      // overpacing when spend% exceeds time% by > 5 pts
const UNDERPACE_PTS   = 0.10;      // underpacing when spend% trails time% by > 10 pts
const WASTE_MIN_SPEND = 500;       // $ spent with ~$0 revenue counts as wasted
const ROAS_FLOOR      = 1.0;       // META ROAS below this triggers a low-ROAS alert
const BUDGET_MODE     = 'revised'; // 'revised' | 'original'

// ---- get CSV text -----------------------------------------------------------
const inJson = $input.first().json;
const csv = inJson.data || inJson.body || (typeof inJson === 'string' ? inJson : '');
if (!csv || typeof csv !== 'string') {
  throw new Error('No CSV text on incoming item — set the HTTP Request node Response Format to "Text".');
}

// ---- CSV parser (quoted fields + embedded newlines) -------------------------
function parseCSV(text) {
  const rows = []; let row = [], field = '', inQ = false;
  for (let i = 0; i < text.length; i++) {
    const ch = text[i];
    if (inQ) {
      if (ch === '"' && text[i + 1] === '"') { field += '"'; i++; }
      else if (ch === '"') { inQ = false; }
      else { field += ch; }
    } else {
      if (ch === '"') inQ = true;
      else if (ch === ',') { row.push(field); field = ''; }
      else if (ch === '\n') { row.push(field); rows.push(row); row = []; field = ''; }
      else if (ch === '\r') { /* skip */ }
      else { field += ch; }
    }
  }
  if (field.length || row.length) { row.push(field); rows.push(row); }
  return rows;
}

// strip $ , % ; treat #REF!/#DIV/0!/#VALUE!/NA/blank/Loading as null
const num = s => {
  const t = String(s == null ? '' : s).trim();
  if (t === '' || /^#|^na$|^loading/i.test(t)) return null;
  const v = parseFloat(t.replace(/[$,%\s]/g, ''));
  return isFinite(v) ? v : null;
};
const pct   = s => { const v = num(s); return v == null ? null : (String(s).includes('%') ? v / 100 : v); };
const money = v => v == null ? '—' : '$' + Math.round(v).toLocaleString();

const rows = parseCSV(csv);

// ---- time pacing + as-of date from the metadata block -----------------------
let timePacing = null, daysLeft = null, asOf = null;
for (const r of rows) {
  const label = (r[1] || '').toLowerCase().trim();
  if (label === 'time pacing') timePacing = pct(r[2]);
  if (label.startsWith('days left')) daysLeft = num(r[2]);
  if (label === 'today') asOf = r[2];
}

// ---- per-client totals = the "All Campaign Spend" subtotal rows -------------
let h = -1;
for (let i = 0; i < rows.length; i++) { if ((rows[i][0] || '').trim() === 'Client') { h = i; break; } }
if (h < 0) throw new Error('Could not find the "Client" header row in the tracker CSV.');

const clients = []; let cur = null;
for (let i = h + 1; i < rows.length; i++) {
  const r = rows[i];
  const c0 = (r[0] || '').replace(/[\r\n]+/g, ' ').replace(/\s+/g, ' ').trim();
  const c1 = (r[1] || '').replace(/\s+/g, ' ').trim();
  if (c0 === 'Client') continue;          // repeated header
  if (c0) cur = c0;                        // client-start row
  if (c1 === 'All Campaign Spend' && cur) {
    const original = num(r[2]), revised = num(r[3]);
    const budget = BUDGET_MODE === 'revised'
      ? (revised != null ? revised : original)
      : (original != null ? original : revised);
    clients.push({
      name: cur,
      budget,
      spend:    num(r[4]) || 0,   // Spend MTD
      revLC:    num(r[8]) || 0,   // Revenue LC MTD
      revMeta:  num(r[9]) || 0,   // Revenue META MTD
      lcRoas:   num(r[10]),       // LC ROAS MTD
      metaRoas: num(r[11]),       // META ROAS MTD
    });
    cur = null;
  }
}

// ---- classify ---------------------------------------------------------------
const over = [], under = [], wasted = [], lowRoas = [];
let totBudget = 0, totSpend = 0, totRevMeta = 0, totRevLC = 0;
for (const c of clients) {
  totSpend += c.spend; totRevMeta += c.revMeta; totRevLC += c.revLC;
  if (c.budget) totBudget += c.budget;
  if (c.budget && c.budget > 0 && timePacing != null) {
    const used = c.spend / c.budget, delta = used - timePacing;
    if (delta > OVERPACE_PTS) over.push({ ...c, used, delta });
    else if (delta < -UNDERPACE_PTS) under.push({ ...c, used, delta });
  }
  if (c.spend > WASTE_MIN_SPEND && (c.revLC + c.revMeta) <= 0) wasted.push(c);
  if (c.metaRoas != null && c.metaRoas < ROAS_FLOOR && c.spend > WASTE_MIN_SPEND) lowRoas.push(c);
}
over.sort((a, b) => b.delta - a.delta);
under.sort((a, b) => a.delta - b.delta);
wasted.sort((a, b) => b.spend - a.spend);
lowRoas.sort((a, b) => a.metaRoas - b.metaRoas);

// ---- build Slack message ----------------------------------------------------
const tp          = timePacing != null ? Math.round(timePacing * 100) + '%' : '—';
const portfUsed   = totBudget > 0 ? Math.round(totSpend / totBudget * 100) + '%' : '—';
const blendedRoas = totSpend > 0 ? (totRevMeta / totSpend).toFixed(2) + '×' : '—';

const L = [];
L.push('*📊 Daily Social Budget Pacing — ' + (asOf || new Date().toISOString().slice(0, 10)) + '*');
L.push('Time pacing *' + tp + '*' + (daysLeft != null ? ' · ' + daysLeft + ' days left' : ''));
L.push('Spend *' + money(totSpend) + '* / ' + money(totBudget) + ' (*' + portfUsed + '* of budget) · META rev ' + money(totRevMeta) + ' · blended ROAS *' + blendedRoas + '*');

const paceLine = c => '• *' + c.name.replace(/\s+/g, ' ') + '* — ' + money(c.spend) + ' / ' + money(c.budget) +
  ' · used ' + Math.round(c.used * 100) + '% (' + (c.delta >= 0 ? '+' : '') + Math.round(c.delta * 100) + 'pts vs time)';

if (over.length)  { L.push(''); L.push('*🔴 Overpacing (>' + Math.round(OVERPACE_PTS * 100) + 'pts)*'); over.forEach(c => L.push(paceLine(c))); }
if (under.length) { L.push(''); L.push('*🟡 Underpacing (<-' + Math.round(UNDERPACE_PTS * 100) + 'pts)*'); under.forEach(c => L.push(paceLine(c))); }
if (wasted.length){ L.push(''); L.push('*💸 Wasted spend (>' + money(WASTE_MIN_SPEND) + ', ~$0 revenue)*'); wasted.forEach(c => L.push('• *' + c.name.replace(/\s+/g, ' ') + '* — ' + money(c.spend) + ' spent, ' + money(c.revLC + c.revMeta) + ' revenue')); }
if (lowRoas.length){ L.push(''); L.push('*📉 Low META ROAS (<' + ROAS_FLOOR.toFixed(1) + '×)*'); lowRoas.forEach(c => L.push('• *' + c.name.replace(/\s+/g, ' ') + '* — ' + c.metaRoas.toFixed(2) + '× on ' + money(c.spend))); }

if (!over.length && !under.length && !wasted.length && !lowRoas.length) {
  L.push(''); L.push('✅ All clients within pacing / ROAS thresholds.');
}

return [{ json: {
  text: L.join('\n'),
  counts: { over: over.length, under: under.length, wasted: wasted.length, lowRoas: lowRoas.length, clients: clients.length },
} }];
